%[text] # Simple Example
%[text] This is a simple example of using regularizeNd.
clc; clear; close all;
%[text] This example uses the `etopo_loihi` sample data packaged with regularizeNd. Data extracted from:
%[text] NOAA National Centers for Environmental Information. 2022: ETOPO 2022 15 Arc-Second Global Relief Model. NOAA National Centers for Environmental Information. DOI: [https://doi.org/10.25921/fd45-gt74](file:vscode-//vscode-app/usr/share/code/resources/app/out/vs/code/electron-browser/workbench/workbench.html). Accessed March 14, 2026.
data = load('etopo_loihi.mat');
x = double(data.x); x2 = x(data.mask);
y = double(data.y); y2 = y(data.mask);
z = double(data.z); z2 = z(data.mask);


xLimits = [min(x), max(x)];
yLimits = [min(y), max(y)];

xGrid = {linspace(xLimits(1) - eps(xLimits(1)), xLimits(2) + eps(xLimits(2)), 120), ...
         linspace(yLimits(1) - eps(yLimits(1)), yLimits(2) + eps(yLimits(2)), 121)};

smoothness = 0.0001;
    
zGrid = regularizeNd([x2,y2], z2, xGrid, smoothness, 'cubic');
% equivalents ways to call regularizeNd
% zGrid = regularizeNd([x,y], z, xGrid, smoothness, 'cubic');
% zGrid = regularizeNd([x,y], z, xGrid, smoothness, 'cubic', 'normal');


scatter3(x2, y2, z2, [], 'r', 'filled') %[output:1a60e218]
hold on; %[output:1a60e218]
surf(xGrid{:}, zGrid','FaceColor','interp','EdgeColor','interp') %[output:1a60e218]
view(31.5,36) %[output:1a60e218]
xlabel('Longitude') %[output:1a60e218]
ylabel('Latitude') %[output:1a60e218]
zlabel('Depth in Feet') %[output:1a60e218]
grid on %[output:1a60e218]
legend({'Scattered Data', 'Regularized Surface'}, 'location', 'best'); %[output:1a60e218]
